class PaymentProcessor {
  static const String _apiKey = 'YOUR_API_KEY';
  static const String _baseUrl = 'https://api.paymentgateway.com';

  static Future<bool> processInAppPurchase(
    String productId, 
    String userId
  ) async {
    try {
      final bool available = await InAppPurchase.instance.isAvailable();
      if (!available) return false;

      final List<PurchaseParam> purchaseParams = [
        PurchaseParam(
          productDetails: await _getProductDetails(productId),
          payload: userId,
        )
      ];

      await InAppPurchase.instance.purchaseStream
          .listen((purchases) {
        if (purchases.isNotEmpty) {
          _handlePurchaseResult(purchases);
        }
      });

      await InAppPurchase.instance.purchase(purchaseParams);
      return true;
    } catch (e) {
      return false;
    }
  }

  static Future<ProductDetails> _getProductDetails(String productId) async {
    final List<String> productIds = [productId];
    final Stream<List<ProductDetails>> productStream = 
        InAppPurchase.instance.queryProductDetails(productIds);
    
    final ProductDetailsResponse response = 
        await productStream.first;
    
    if (response.error != null) {
      throw Exception('Error fetching product details');
    }
    
    return response.productDetails.first;
  }

  static void _handlePurchaseResult(List<PurchaseDetails> purchases) {
    for (PurchaseDetails purchase in purchases) {
      if (purchase.status == PurchaseStatus.purchased ||
          purchase.status == PurchaseStatus.restored) {
        _sendTransactionToServer(purchase);
        InAppPurchase.instance.completePurchase(purchase);
      } else if (purchase.status == PurchaseStatus.canceled) {
        // Handle cancellation
      } else if (purchase.status == PurchaseStatus.error) {
        // Handle error
      }
    }
  }

  static Future<bool> processMobileWallet(
    Map<String, dynamic> transactionData,
    String walletType
  ) async {
    try {
      final String url = '${_baseUrl}/transactions';
      
      final http.Response response = await http.post(
        Uri.parse(url),
        headers: {
          'Content-Type': 'application/json',
          'Authorization': 'Bearer $_apiKey'
        },
        body: jsonEncode({
          'amount': transactionData['amount'],
          'currency': transactionData['currency'],
          'wallet_type': walletType,
          'user_id': transactionData['user_id'],
          'description': transactionData['description'],
          'token': transactionData['token'],
          'metadata': transactionData['metadata']
        }),
      );

      if (response.statusCode == 200) {
        final Map<String, dynamic> result = jsonDecode(response.body);
        return result['success'] == true;
      }
      return false;
    } catch (e) {
      return false;
    }
  }

  static Future<void> _sendTransactionToServer(PurchaseDetails purchase) async {
    try {
      final String url = '${_baseUrl}/inapp/transaction';
      
      await http.post(
        Uri.parse(url),
        headers: {
          'Content-Type': 'application/json',
          'Authorization': 'Bearer $_apiKey'
        },
        body: jsonEncode({
          'transaction_id': purchase.purchaseID,
          'product_id': purchase.productID,
          'amount': purchase.originalPrice,
          'currency': purchase.currencyCode,
          'user_id': purchase.payload,
          'status': 'completed',
          'timestamp': DateTime.now().toIso8601String(),
        }),
      );
    } catch (e) {
      // Log error but don't fail the purchase
    }
  }

  static Future<bool> validateCardToken(String token) async {
    try {
      final String url = '${_baseUrl}/validate/card';
      
      final http.Response response = await http.post(
        Uri.parse(url),
        headers: {
          'Content-Type': 'application/json',
          'Authorization': 'Bearer $_apiKey'
        },
        body: jsonEncode({
          'token': token,
        }),
      );

      if (response.statusCode == 200) {
        final Map<String, dynamic> result = jsonDecode(response.body);
        return result['valid'] == true;
      }
      return false;
    } catch (e) {
      return false;
    }
  }

  static Future<Map<String, dynamic>> createSecurePayment(
    Map<String, dynamic> paymentData
  ) async {
    try {
      final String url = '${_baseUrl}/secure/payment';
      
      final http.Response response = await http.post(
        Uri.parse(url),
        headers: {
          'Content-Type': 'application/json',
          'Authorization': 'Bearer $_apiKey'
        },
        body: jsonEncode({
          'amount': paymentData['amount'],
          'currency': paymentData['currency'],
          'user_id': paymentData['user_id'],
          'description': paymentData['description'],
          'card_token': paymentData['card_token'],
          'return_url': paymentData['return_url'],
          'metadata': paymentData['metadata'],
        }),
      );

      if (response.statusCode == 200) {
        return jsonDecode(response.body);
      }
      return {'error': 'Payment processing failed'};
    } catch (e) {
      return {'error': 'Network error'};
    }
  }

  static Future<void> setupPushNotifications() async {
    await FirebaseMessaging.onMessage.listen((RemoteMessage message) {
      // Handle incoming push notifications for payment updates
    });

    await FirebaseMessaging.onMessageOpenedApp.listen((RemoteMessage message) {
      // Handle when app is opened from notification
    });
  }

  static Future<bool> verifyTransaction(String transactionId) async {
    try {
      final String url = '${_baseUrl}/transaction/$transactionId/verify';
      
      final http.Response response = await http.get(
        Uri.parse(url),
        headers: {
          'Authorization': 'Bearer $_apiKey'
        },
      );

      if (response.statusCode == 200) {
        final Map<String, dynamic> result = jsonDecode(response.body);
        return result['verified'] == true;
      }
      return false;
    } catch (e) {
      return false;
    }
  }
}

class SecurePaymentWidget extends StatelessWidget {
  final Function(String) onPaymentSuccess;
  final Function(String) onPaymentFailure;
  final double amount;
  final String currency;
  final String description;

  const SecurePaymentWidget({
    Key? key,
    required this.onPaymentSuccess,
    required this.onPaymentFailure,
    required this.amount,
    required this.currency,
    required this.description,
  }) : super(key: key);

  @override
  Widget build(BuildContext context) {
    return Card(
      elevation: 4,
      child: Padding(
        padding: const EdgeInsets.all(16.0),
        child: Column(
          mainAxisSize: MainAxisSize.min,
          children: [
            Text('Amount: \$${amount.toStringAsFixed(2)}'),
            Text(description),
            ElevatedButton(
              onPressed: () => _processSecurePayment(context),
              child: Text('Process Payment'),
            ),
          ],
        ),
      ),
    );
  }

  Future<void> _processSecurePayment(BuildContext context) async {
    final Map<String, dynamic> paymentData = {
      'amount': amount,
      'currency': currency,
      'user_id': 'current_user_id', // Replace with actual user ID
      'description': description,
      'return_url': 'https://yourapp.com/payment-success',
    };

    try {
      final Map<String, dynamic> result = 
          await PaymentProcessor.createSecurePayment(paymentData);
      
      if (result['error'] != null) {
        onPaymentFailure(result['error']);
      } else {
        onPaymentSuccess(result['transaction_id']);
      }
    } catch (e) {
      onPaymentFailure('Payment processing error');
    }
  }
}